import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as i,c as a,b as t}from"./app-6ef940c3.js";const r="/assets/未命名文件-01769812.png",o="/assets/image-20240124170017818-1db4f841.png",s={},n=t('<h2 id="功能介绍" tabindex="-1"><a class="header-anchor" href="#功能介绍" aria-hidden="true">#</a> 功能介绍</h2><p>积分商城项目：简单来说就是客户在银行存钱，会产生相应的积分，然后客户可以在积分商城里面使用积分购物，由于客户的积分按照每年清空，并且积分商城会在一些节假日有活动，虽然平常使用的人数并不多，但是每逢节假日或者年末，积分商城的访问量就会增多，因此整个项目总体还是直接采用比较流行的微服务架构，并且需要考虑高并发</p><p>商品三级分类功能（eg：手机&gt;手机配件&gt;手机充电器），三级分类这种数据通常不怎么会变化，但是客户基本上访问商城首页的时候，都会发起该请求，所以考虑到将该部分数据放入redis中，以此来减轻系统压力</p><h2 id="哪些数据适合放入缓存" tabindex="-1"><a class="header-anchor" href="#哪些数据适合放入缓存" aria-hidden="true">#</a> 哪些数据适合放入缓存</h2><ul><li>即时性，数据一致性要求不高</li><li>访问量大，更新频率不大（读多，写少）</li></ul><h2 id="基本请求流程" tabindex="-1"><a class="header-anchor" href="#基本请求流程" aria-hidden="true">#</a> 基本请求流程</h2><figure><img src="'+r+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="需要考虑的问题" tabindex="-1"><a class="header-anchor" href="#需要考虑的问题" aria-hidden="true">#</a> 需要考虑的问题</h2><ul><li>缓存穿透</li><li>缓存击穿</li><li>缓存雪崩</li></ul><blockquote><p>分布式下如何加锁？</p></blockquote><p>如果是本地加锁，比如有3个<code>jfmall-product</code>服务，每个服务都有10000个请求去redis中查找数据，由于是对本地加锁，那么3个服务，一共3万个请求，就可能会出现，3个服务中，同时总共<strong>有3个请求</strong>去redis中查找数据，发现redis中没有数据，然后就都<strong>会去数据库中查找</strong>，所以可以考虑用<strong>分布式锁</strong></p><figure><img src="'+o+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure>',12),d=[n];function c(l,h){return i(),a("div",null,d)}const f=e(s,[["render",c],["__file","商品三级分类.html.vue"]]);export{f as default};
